/**
 * 上海3D街道地图 - 高德真实地图版本（带区域划分）
 */

import { AREAS_DATA } from './map-areas.js';

// ==================== 配置 ====================
const CONFIG = {
    AMAP_KEY: '6fc614d0454e138a426ed6735b5989c8',
    CENTER: [121.4737, 31.2304],
    DEFAULT_ZOOM: 14,
    ENABLE_3D_BUILDINGS: true
};

// ==================== 全局变量 ====================
let map = null;
let isNightMode = false;
let isAutoRotating = false;
let currentInfoWindow = null;
let areaCircles = []; // 存储区域圆形
let famousPointMarkers = []; // 存储著名点标记
let currentArea = null; // 当前选中的区域

// ==================== 初始化 ====================
function init() {
    if (typeof AMap === 'undefined') {
        console.error('高德地图API未加载');
        showApiKeyNotice();
        return;
    }

    initMap();
    bindEvents();
    
    setTimeout(() => {
        document.getElementById('loading').classList.add('hidden');
    }, 1500);
}

// ==================== 地图初始化 ====================
function initMap() {
    try {
        map = new AMap.Map('amap-container', {
            viewMode: '3D',
            pitch: 60,
            zoom: CONFIG.DEFAULT_ZOOM,
            center: CONFIG.CENTER,
            mapStyle: 'amap://styles/darkblue',
            showBuildingBlock: true,
            buildingAnimation: true,
            skyColor: '#1a1a2e'
        });

        // 添加3D建筑图层
        if (CONFIG.ENABLE_3D_BUILDINGS) {
            addBuildingsLayer();
        }

        // 添加区域划分
        addAreaCircles();
        
        // 添加控件
        addControls();

        console.log('高德地图初始化成功');

    } catch (error) {
        console.error('高德地图初始化失败:', error);
        document.getElementById('loading').innerHTML = '<p>地图加载失败，请检查API Key</p>';
    }
}

// ==================== 添加3D建筑图层 ====================
function addBuildingsLayer() {
    try {
        const buildings = new AMap.Buildings({
            zooms: [14, 20],
            zIndex: 10,
            heightFactor: 1.5,
            visible: true
        });
        map.add(buildings);
    } catch (error) {
        console.warn('3D建筑图层加载失败:', error);
    }
}

// ==================== 添加区域圆形划分 ====================
function addAreaCircles() {
    AREAS_DATA.forEach(area => {
        // 创建圆形区域
        const circle = new AMap.Circle({
            center: area.center,
            radius: area.radius,
            fillColor: area.color,
            fillOpacity: 0.2,
            strokeColor: area.color,
            strokeWeight: 2,
            strokeOpacity: 0.8,
            zIndex: 50,
            extData: area // 存储区域数据
        });

        // 点击事件
        circle.on('click', () => {
            showAreaInfo(area);
        });

        // 鼠标悬停效果
        circle.on('mouseover', () => {
            circle.setFillOpacity(0.4);
            circle.setStrokeWeight(4);
        });

        circle.on('mouseout', () => {
            if (currentArea !== area) {
                circle.setFillOpacity(0.2);
                circle.setStrokeWeight(2);
            }
        });

        map.add(circle);
        areaCircles.push(circle);

        // 添加区域中心标记
        const centerMarker = new AMap.Marker({
            position: area.center,
            title: area.name,
            label: {
                content: `<div style="background: ${area.color}; color: white; padding: 5px 10px; border-radius: 4px; font-size: 12px; font-weight: bold;">${area.name}</div>`,
                offset: new AMap.Pixel(0, -30)
            },
            extData: area
        });

        centerMarker.on('click', () => {
            showAreaInfo(area);
        });

        map.add(centerMarker);
    });
}

// ==================== 显示区域信息 ====================
function showAreaInfo(area) {
    currentArea = area;
    
    // 高亮当前区域
    areaCircles.forEach(circle => {
        const circleData = circle.getExtData();
        if (circleData.id === area.id) {
            circle.setFillOpacity(0.5);
            circle.setStrokeWeight(5);
        } else {
            circle.setFillOpacity(0.1);
            circle.setStrokeWeight(1);
        }
    });

    // 显示著名点
    showFamousPoints(area);

    // 显示信息面板
    showAreaPanel(area);

    // 飞转到区域
    map.setZoomAndCenter(16, area.center);
}

// ==================== 显示区域内著名点 ====================
function showFamousPoints(area) {
    // 清除之前的著名点
    clearFamousPoints();

    // 添加新的著名点
    area.famousPoints.forEach((point, index) => {
        const marker = new AMap.Marker({
            position: point.position,
            title: point.name,
            icon: new AMap.Icon({
                size: new AMap.Size(25, 25),
                image: 'https://webapi.amap.com/theme/v1.3/markers/n/mark_b.png',
                imageSize: new AMap.Size(25, 25)
            }),
            offset: new AMap.Pixel(-12, -25),
            animation: 'AMAP_ANIMATION_DROP',
            extData: { ...point, areaName: area.name }
        });

        // 点击显示详细信息
        marker.on('click', () => {
            showFamousPointInfo(point, area);
        });

        map.add(marker);
        famousPointMarkers.push(marker);

        // 延迟显示，形成动画效果
        setTimeout(() => {
            marker.show();
        }, index * 100);
    });
}

// ==================== 清除著名点 ====================
function clearFamousPoints() {
    famousPointMarkers.forEach(marker => {
        map.remove(marker);
    });
    famousPointMarkers = [];
}

// ==================== 显示著名点信息 ====================
function showFamousPointInfo(point, area) {
    if (currentInfoWindow) {
        currentInfoWindow.close();
    }

    const content = `
        <div style="padding: 10px; max-width: 280px;">
            <h3 style="margin-bottom: 8px; color: #1a1a2e; font-size: 16px;">${point.name}</h3>
            <span style="display: inline-block; padding: 3px 8px; background: ${area.color}; color: white; border-radius: 12px; font-size: 11px; margin-bottom: 8px;">${area.name}</span>
            <p style="color: #666; font-size: 13px; line-height: 1.5;">${point.description}</p>
        </div>
    `;

    currentInfoWindow = new AMap.InfoWindow({
        content: content,
        position: point.position,
        offset: new AMap.Pixel(0, -30),
        autoMove: true
    });

    currentInfoWindow.open(map);
}

// ==================== 显示区域面板 ====================
function showAreaPanel(area) {
    const panel = document.getElementById('info-panel');
    const title = document.getElementById('info-title');
    const content = document.getElementById('info-content');

    title.textContent = area.name;
    
    let html = `<div class="icon" style="font-size: 48px; text-align: center; margin-bottom: 15px;">🎯</div>`;
    html += `<span class="tag" style="display: inline-block; padding: 4px 10px; background: ${area.color}; color: white; border-radius: 20px; font-size: 12px; margin-bottom: 10px;">特色区域</span>`;
    html += `<p style="margin-bottom: 10px; color: #555;">${area.description}</p>`;
    
    html += `<h3 style="color: #1a1a2e; font-size: 16px; margin-top: 15px; margin-bottom: 8px; padding-bottom: 5px; border-bottom: 2px solid ${area.color};">🛣️ 包含街道</h3>`;
    html += `<p style="margin-bottom: 10px; color: #555;">${area.streets.join('、')}</p>`;
    
    html += `<h3 style="color: #1a1a2e; font-size: 16px; margin-top: 15px; margin-bottom: 8px; padding-bottom: 5px; border-bottom: 2px solid ${area.color};">📍 著名地点 (${area.famousPoints.length}个)</h3>`;
    html += `<ul style="margin-bottom: 10px; color: #555; padding-left: 20px;">`;
    area.famousPoints.forEach(point => {
        html += `<li style="margin-bottom: 5px;">${point.name}</li>`;
    });
    html += `</ul>`;
    
    html += `<p style="margin-top: 15px; color: #888; font-size: 12px; text-align: center;">💡 点击地图上的蓝色标记查看详细信息</p>`;
    
    content.innerHTML = html;
    panel.classList.remove('hidden');
}

// ==================== 添加地图控件 ====================
function addControls() {
    map.addControl(new AMap.Scale());
    map.addControl(new AMap.ToolBar({
        position: 'RB'
    }));
}

// ==================== 绑定事件 ====================
function bindEvents() {
    window.addEventListener('resize', () => {
        if (map) {
            map.resize();
        }
    });

    document.getElementById('reset-view').addEventListener('click', resetView);
    document.getElementById('toggle-rotate').addEventListener('click', toggleRotation);
    document.getElementById('zoom-in').addEventListener('click', () => zoom(1));
    document.getElementById('zoom-out').addEventListener('click', () => zoom(-1));
    document.getElementById('close-info').addEventListener('click', closeInfoPanel);
    document.getElementById('night-mode').addEventListener('click', toggleNightMode);

    bindSidebarNavigation();
}

// ==================== 绑定侧边栏导航 ====================
function bindSidebarNavigation() {
    const areaList = document.getElementById('area-list');
    if (!areaList) return;

    AREAS_DATA.forEach(area => {
        const li = document.createElement('li');
        li.textContent = area.name;
        li.style.borderLeft = `4px solid ${area.color}`;
        li.addEventListener('click', () => {
            showAreaInfo(area);
        });
        areaList.appendChild(li);
    });
}

// ==================== 控制功能 ====================
function resetView() {
    if (!map) return;
    
    // 清除区域高亮
    areaCircles.forEach(circle => {
        circle.setFillOpacity(0.2);
        circle.setStrokeWeight(2);
    });
    
    // 清除著名点
    clearFamousPoints();
    
    currentArea = null;
    
    map.setZoomAndCenter(CONFIG.DEFAULT_ZOOM, CONFIG.CENTER);
    map.setPitch(60);
    
    if (currentInfoWindow) {
        currentInfoWindow.close();
    }
    closeInfoPanel();
}

function toggleRotation() {
    if (!map) return;
    
    isAutoRotating = !isAutoRotating;
    const btn = document.getElementById('toggle-rotate');
    btn.textContent = isAutoRotating ? '停止旋转' : '自动旋转';
    btn.style.background = isAutoRotating ? 'rgba(0, 212, 255, 0.3)' : '';
    
    if (isAutoRotating) {
        startRotation();
    } else {
        stopRotation();
    }
}

let rotationInterval = null;
function startRotation() {
    if (rotationInterval) return;
    
    let rotation = 0;
    rotationInterval = setInterval(() => {
        rotation += 0.5;
        map.setRotation(rotation);
    }, 50);
}

function stopRotation() {
    if (rotationInterval) {
        clearInterval(rotationInterval);
        rotationInterval = null;
    }
}

function zoom(direction) {
    if (!map) return;
    const currentZoom = map.getZoom();
    map.setZoom(currentZoom + direction);
}

function toggleNightMode() {
    if (!map) return;
    
    isNightMode = !isNightMode;
    const btn = document.getElementById('night-mode');
    
    if (isNightMode) {
        btn.textContent = '☀️ 日间模式';
        btn.classList.add('active');
        map.setMapStyle('amap://styles/darkblue');
    } else {
        btn.textContent = '🌙 夜景模式';
        btn.classList.remove('active');
        map.setMapStyle('amap://styles/normal');
    }
}

function closeInfoPanel() {
    document.getElementById('info-panel').classList.add('hidden');
}

function showApiKeyNotice() {
    document.getElementById('api-key-notice').style.display = 'block';
    setTimeout(() => {
        document.getElementById('api-key-notice').style.display = 'none';
    }, 5000);
}

// ==================== 启动 ====================
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
} else {
    init();
}
