/**
 * 获取区域数据
 */
export function getAreaById(id) {
    return AREAS_DATA.find(area => area.id === id);
}

/**
 * 获取所有区域
 */
export function getAllAreas() {
    return AREAS_DATA;
}

/**
 * 根据位置查找最近的区域
 */
export function findNearestArea(position) {
    let nearest = null;
    let minDistance = Infinity;
    
    AREAS_DATA.forEach(area => {
        const distance = AMap.GeometryUtil.distance(position, area.center);
        if (distance < minDistance) {
            minDistance = distance;
            nearest = area;
        }
    });
    
    return nearest;
}
